import { useState } from "react";
import { toast } from "react-toastify";
import { useAuth } from "../context/AuthContext";

const AuthPage = () => {
  const { login, register } = useAuth();
  const [isLogin, setIsLogin] = useState(true);
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [loading, setLoading] = useState(false);

  async function handle() {
    if (!form.email || !form.password) {
      toast.error("Please fill all fields");
      return;
    }
    if (!isLogin && !form.name.trim()) {
      toast.error("Please enter your name");
      return;
    }
    setLoading(true);
    try {
      if (isLogin) await login(form.email, form.password);
      else await register(form.name.trim(), form.email, form.password);
      toast.success(
        isLogin ? "Welcome back! 👋" : "Account created! Let's learn! 🎉",
      );
    } catch (err) {
      toast.error(err.response?.data?.message || "Something went wrong");
    } finally {
      setLoading(false);
    }
  }

  const inp = {
    padding: "14px 16px",
    borderRadius: 12,
    width: "100%",
    border: "1px solid rgba(99,102,241,.3)",
    background: "#0f172a",
    color: "#e2e8f0",
    fontSize: 15,
    outline: "none",
  };

  return (
    <div
      className="min-h-screen flex items-center justify-center px-4"
      style={{
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "linear-gradient(135deg,#0f172a,#1e293b)",
        padding: 16,
      }}
    >
      <div className="w-full max-w-md fade-in">
        {/* Logo */}
        <div className="text-center mb-8">
          <h1 className="font-playfair text-5xl text-white mb-2">SpeakUp</h1>
          <p className="text-blue-200 text-sm">
            🗣️ Your smart English learning companion
          </p>
        </div>

        <div
          className="rounded-3xl shadow-2xl p-8"
          style={{
            width: "100%",
            maxWidth: 400,
            background: "rgba(30,41,59,.97)",
            borderRadius: 24,
            padding: 40,
            boxShadow: "0 25px 50px rgba(0,0,0,.5)",
            border: "1px solid rgba(99,102,241,.3)",
          }}
        >
          <h2 className="text-2xl font-extrabold text-gray-300 mb-1">
            {isLogin ? "Welcome Back!" : "Create Account"}
          </h2>
          <p className="text-sm text-slate-400 mb-6">
            {isLogin
              ? "Continue your learning journey"
              : "Start your English journey today"}
          </p>

          <div className="space-y-3">
            {!isLogin && (
              <input
                className={`${inp} bg-[#4d4b5d] focus:bg-[#4d4b5d] focus:border-gray-500`}
                placeholder="Full Name"
                name="name"
                value={form.name}
                onChange={(e) =>
                  setForm((f) => ({ ...f, name: e.target.value }))
                }
              />
            )}
            <input
            style={{inp}}
              className={`${inp} bg-[#4d4b5d] focus:bg-[#4d4b5d] focus:border-gray-500`}
              placeholder="Email Address"
              type="email"
              id="email"
              name="email"
              value={form.email}
              onChange={(e) =>
                setForm((f) => ({ ...f, email: e.target.value }))
              }
            />
            <input
              className={`${inp} bg-[#4d4b5d] focus:bg-[#4d4b5d] focus:border-gray-500`}
              placeholder="Password"
              type="password"
              value={form.password}
              onChange={(e) =>
                setForm((f) => ({ ...f, password: e.target.value }))
              }
              onKeyDown={(e) => e.key === "Enter" && handle()}
            />
          </div>

          <button
            onClick={handle}
            disabled={loading}
            className="mt-5 w-full bg-blue-900 hover:bg-blue-800 disabled:opacity-50 text-white font-bold py-3.5 rounded-xl text-sm transition-all duration-200 hover:-translate-y-0.5 active:translate-y-0"
          >
            {loading
              ? "Please wait..."
              : isLogin
                ? "Login →"
                : "Create Account →"}
          </button>

          <p className="text-xs text-gray-300 text-center mt-5">
            {isLogin ? "Don't have an account? " : "Already registered? "}
            <span
              className="text-blue-400 font-bold cursor-pointer hover:underline"
              onClick={() => {
                setIsLogin((l) => !l);
                setForm({ name: "", email: "", password: "" });
              }}
            >
              {isLogin ? "Sign up free" : "Login"}
            </span>
          </p>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
